#include<bits/stdc++.h>
using namespace std;
long long t,n,ans,dp[100005];
struct node
{
    long long a,b,c;
    bool operator<(const node other) const
    {
        return other.b*c<(b*other.c);
    }
} a[100005];
int main()
{
    cin>>t>>n;
    for(int i=1;i<=n;i++) cin>>a[i].a;
    for(int i=1;i<=n;i++) cin>>a[i].b;
    for(int i=1;i<=n;i++) cin>>a[i].c;
    sort(a+1,a+1+n);
    for(int i=1;i<=n;i++)
    {
        for(int j=t;j>=a[i].c;j--)
        {
            dp[j]=max(dp[j],dp[j-a[i].c]+a[i].a-(a[i].b*j));
            ans=max(ans,dp[j]);
        }
    }
    cout<<ans;
    return 0;
}
